183		hosts, err := s.store.ListHosts(r.Context(), filter)
184		if err != nil {
185			s.logger.Error("list hosts", "error", err)
186			writeError(w, http.StatusInternalServerError, "failed to list hosts")
187			return
188		}
189	
190		// For non-admin, scope to owned CAs
191		if !actorIsAdmin(r.Context()) {
192			actor := ActorOf(r.Context())
193			if actor == nil {
194				writeJSON(w, http.StatusOK, []*models.Host{})
195				return
196			}
197			cas, err := s.store.ListCAsByOwner(r.Context(), actor.ID)
198			if err != nil {
199				s.logger.Error("list cas by owner", "error", err)
200				writeError(w, http.StatusInternalServerError, "failed to check permissions")
201				return
202			}
203			ownedCAIDs := make(map[string]struct{}, len(cas))
204			for _, ca := range cas {
