32	// the DB-backed operator API keys and attaches the matching operator to the
33	// request context. Requests that pass through are guaranteed to have a
34	// non-nil ActorOf(ctx).
35	func bearerAuth(s store.Store) func(http.Handler) http.Handler {
36		return func(next http.Handler) http.Handler {
37			return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
38				auth := r.Header.Get("Authorization")
39				if auth == "" {
40					writeError(w, http.StatusUnauthorized, "missing authorization header")
41					return
42				}
43	
