45				if token == auth || token == "" {
46					writeError(w, http.StatusUnauthorized, "invalid API key")
47					return
48				}
49	
50				sum := sha256.Sum256([]byte(token))
51				hash := hex.EncodeToString(sum[:])
52				op, key, err := s.GetOperatorByAPIKeyHash(r.Context(), hash)
53				switch {
54				case err == nil:
55					// Best-effort last_used_at update; ignore failure.
56					if err := s.TouchOperatorAPIKey(r.Context(), key.ID, time.Now()); err != nil {
57						slog.Debug("touch api key", "error", err)
58					}
59					next.ServeHTTP(w, r.WithContext(withActor(r.Context(), op)))
60					return
61				case !errors.Is(err, store.ErrNotFound):
62					slog.Error("auth lookup", "error", err)
63					writeError(w, http.StatusInternalServerError, "auth lookup failed")
64					return
65				}
66	
67				writeError(w, http.StatusUnauthorized, "invalid API key")
68			})
69		}
70	}
