33	// handleListCAs returns all CAs visible to the actor. Admin sees all,
34	// non-admin sees only CAs they own.
35	func (s *Server) handleListCAs(w http.ResponseWriter, r *http.Request) {
36		var (
37			cas []*models.CA
38			err error
39		)
40		if actorIsAdmin(r.Context()) {
41			cas, err = s.store.ListCAs(r.Context())
42		} else {
43			cas, err = s.store.ListCAsByOwner(r.Context(), ActorOf(r.Context()).ID)
44		}
45		if err != nil {
46			s.logger.Error("list CAs", "error", err)
47			writeError(w, http.StatusInternalServerError, "failed to list CAs")
48			return
49		}
50		out := make([]caResponse, 0, len(cas))
51		for _, c := range cas {
52			out = append(out, s.toCAResponse(c))
53		}
