57	func (s *Server) handleGetCAByID(w http.ResponseWriter, r *http.Request) {
58		id := chi.URLParam(r, "id")
59		c, err := s.store.GetCA(r.Context(), id)
60		if errors.Is(err, store.ErrNotFound) {
61			writeError(w, http.StatusNotFound, "CA not found")
62			return
63		}
64		if err != nil {
65			writeError(w, http.StatusInternalServerError, "failed to get CA")
66			return
67		}
68		if !s.canAccessCA(r, c) {
69			writeError(w, http.StatusForbidden, "you do not own this CA")
70			return
71		}
72		writeJSON(w, http.StatusOK, s.toCAResponse(c))
