19	// maxBodySize returns middleware that limits the size of request bodies.
20	func maxBodySize(maxBytes int64) func(http.Handler) http.Handler {
21		return func(next http.Handler) http.Handler {
22			return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
23				if r.Body != nil {
24					r.Body = http.MaxBytesReader(w, r.Body, maxBytes)
25				}
26				next.ServeHTTP(w, r)
27			})
28		}
29	}
30	
31	// bearerAuth returns middleware that authenticates the Bearer token against
32	// the DB-backed operator API keys and attaches the matching operator to the
33	// request context. Requests that pass through are guaranteed to have a
34	// non-nil ActorOf(ctx).
35	func bearerAuth(s store.Store) func(http.Handler) http.Handler {
36		return func(next http.Handler) http.Handler {
37			return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
38				auth := r.Header.Get("Authorization")
39				if auth == "" {
40					writeError(w, http.StatusUnauthorized, "missing authorization header")
41					return
42				}
43	
44				token := strings.TrimPrefix(auth, "Bearer ")
45				if token == auth || token == "" {
46					writeError(w, http.StatusUnauthorized, "invalid API key")
47					return
48				}
49	
50				sum := sha256.Sum256([]byte(token))
51				hash := hex.EncodeToString(sum[:])
52				op, key, err := s.GetOperatorByAPIKeyHash(r.Context(), hash)
53				switch {
54				case err == nil:
55					// Best-effort last_used_at update; ignore failure.
56					if err := s.TouchOperatorAPIKey(r.Context(), key.ID, time.Now()); err != nil {
57						slog.Debug("touch api key", "error", err)
58					}
59					next.ServeHTTP(w, r.WithContext(withActor(r.Context(), op)))
60					return
61				case !errors.Is(err, store.ErrNotFound):
62					slog.Error("auth lookup", "error", err)
63					writeError(w, http.StatusInternalServerError, "auth lookup failed")
64					return
65				}
66	
67				writeError(w, http.StatusUnauthorized, "invalid API key")
68			})
69		}
70	}
71	
72	// requestLogger returns middleware that logs requests.
73	func requestLogger(logger *slog.Logger) func(http.Handler) http.Handler {
74		return func(next http.Handler) http.Handler {
75			return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
76				start := time.Now()
77				ww := &responseWriter{ResponseWriter: w, status: http.StatusOK}
78				next.ServeHTTP(ww, r)
79				logger.Info("request",
80					"method", r.Method,
81					"path", r.URL.Path,
82					"status", ww.status,
83					"duration", time.Since(start),
84				)
85			})
86		}
87	}
88	
89	type responseWriter struct {
90		http.ResponseWriter
91		status int
92	}
93	
94	func (rw *responseWriter) WriteHeader(code int) {
95		rw.status = code
96		rw.ResponseWriter.WriteHeader(code)
97	}
98	
99	// rateLimitMiddleware applies the per-IP token-bucket limiter for the
100	// named route group. When the server has no limiter wired up (Enabled=
101	// false in config) requests pass through unchanged.
102	func (s *Server) rateLimitMiddleware(group string) func(http.Handler) http.Handler {
103		return func(next http.Handler) http.Handler {
104			return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
105				if s.limiter == nil {
106					next.ServeHTTP(w, r)
107					return
108				}
109				ip := s.limiter.ClientIP(r)
110				ok, retry := s.limiter.Allow(ip, group)
111				if !ok {
112					ratelimit.WriteRetryAfter(w, retry)
113					return
114				}
115				next.ServeHTTP(w, r)
116			})
117		}
118	}
119	
120	// metricsMiddleware records every served HTTP request and its server-side
121	// latency on the server's private Prometheus registry. The route label is the
122	// chi route pattern (e.g. /api/v1/hosts/{id}) rather than the raw URL, so the
123	// label cardinality stays bounded by the number of declared routes.
124	func (s *Server) metricsMiddleware() func(http.Handler) http.Handler {
125		return func(next http.Handler) http.Handler {
126			return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
127				start := time.Now()
128				ww := &responseWriter{ResponseWriter: w, status: http.StatusOK}
129				next.ServeHTTP(ww, r)
130	
131				if s.metrics == nil {
132					return
133				}
134				route := chi.RouteContext(r.Context()).RoutePattern()
135				if route == "" {
136					route = r.URL.Path
137				}
138				s.metrics.httpRequests.WithLabelValues(r.Method, route, strconv.Itoa(ww.status)).Inc()
139				s.metrics.httpDuration.WithLabelValues(r.Method, route).Observe(time.Since(start).Seconds())
140			})
141		}
142	}
