56	func (s *Server) handleListNetworks(w http.ResponseWriter, r *http.Request) {
57		networks, err := s.store.ListNetworks(r.Context())
58		if err != nil {
59			s.logger.Error("list networks", "error", err)
60			writeError(w, http.StatusInternalServerError, "failed to list networks")
61			return
62		}
63		if !actorIsAdmin(r.Context()) {
64			actor := ActorOf(r.Context())
65			if actor == nil {
66				writeJSON(w, http.StatusOK, []*models.Network{})
67				return
68			}
69			cas, err := s.store.ListCAsByOwner(r.Context(), actor.ID)
70			if err != nil {
71				s.logger.Error("list cas by owner", "error", err)
72				writeError(w, http.StatusInternalServerError, "failed to scope networks")
73				return
74			}
75			owned := make(map[string]struct{}, len(cas))
76			for _, ca := range cas {
77				owned[ca.ID] = struct{}{}
78			}
79			filtered := networks[:0]
80			for _, n := range networks {
81				if _, ok := owned[n.CAID]; ok {
82					filtered = append(filtered, n)
83				}
84			}
85			networks = filtered
86		}
87		writeJSON(w, http.StatusOK, networks)
88	}
