131	func (s *Server) handleCreateOperatorAPIKey(w http.ResponseWriter, r *http.Request) {
132		if !actorIsAdmin(r.Context()) {
133			writeError(w, http.StatusForbidden, "operator management requires the admin role")
134			return
135		}
136		id := chi.URLParam(r, "id")
137		if _, err := s.store.GetOperator(r.Context(), id); err != nil {
138			if errors.Is(err, store.ErrNotFound) {
139				writeError(w, http.StatusNotFound, "operator not found")
140				return
141			}
142			s.logger.Error("get operator", "error", err)
143			writeError(w, http.StatusInternalServerError, "failed to load operator")
144			return
145		}
146		var req createAPIKeyRequest
147		if r.ContentLength > 0 {
148			_ = json.NewDecoder(r.Body).Decode(&req)
149		}
150	
151		keyBytes := make([]byte, 32)
152		if _, err := rand.Read(keyBytes); err != nil {
153			writeError(w, http.StatusInternalServerError, "failed to generate api key")
154			return
155		}
156		plaintext := hex.EncodeToString(keyBytes)
157		sum := sha256.Sum256([]byte(plaintext))
158	
159		entry := &models.OperatorAPIKey{
160			ID:         uuid.New().String(),
161			OperatorID: id,
162			Name:       req.Name,
163			KeyHash:    hex.EncodeToString(sum[:]),
164		}
165		if err := s.store.CreateOperatorAPIKey(r.Context(), entry); err != nil {
166			s.logger.Error("create api key", "error", err)
167			writeError(w, http.StatusInternalServerError, "failed to store api key")
168			return
169		}
170		s.recordAuditAction(r.Context(), auditOperatorAPIKeyCreate, id, entry.ID)
171		writeJSON(w, http.StatusCreated, createAPIKeyResponse{Key: plaintext, Entry: entry})
172	}
