174	func (s *Server) handleRevokeOperatorAPIKey(w http.ResponseWriter, r *http.Request) {
175		if !actorIsAdmin(r.Context()) {
176			writeError(w, http.StatusForbidden, "operator management requires the admin role")
177			return
178		}
179		id := chi.URLParam(r, "id")
180		kid := chi.URLParam(r, "kid")
181		if _, err := s.store.GetOperator(r.Context(), id); err != nil {
182			if errors.Is(err, store.ErrNotFound) {
183				writeError(w, http.StatusNotFound, "operator not found")
184				return
185			}
186			s.logger.Error("get operator", "error", err)
187			writeError(w, http.StatusInternalServerError, "failed to look up operator")
188			return
189		}
190		// Verify the API key belongs to this operator before revoking, so the
191		// audit row reflects the key's real owner — not whichever {id} the
192		// caller supplied in the URL.
193		key, err := s.store.GetOperatorAPIKey(r.Context(), kid)
194		if err != nil {
195			if errors.Is(err, store.ErrNotFound) {
196				writeError(w, http.StatusNotFound, "api key not found")
197				return
198			}
199			s.logger.Error("get api key", "error", err)
200			writeError(w, http.StatusInternalServerError, "failed to look up api key")
201			return
202		}
203		if key.OperatorID != id {
204			writeError(w, http.StatusNotFound, "api key not found")
205			return
206		}
207		if key.RevokedAt != nil {
208			// Already revoked. API stays idempotent — 204 with no new audit row.
209			w.WriteHeader(http.StatusNoContent)
210			return
211		}
212		if err := s.store.RevokeOperatorAPIKey(r.Context(), kid); err != nil {
213			if errors.Is(err, store.ErrNotFound) {
214				// Concurrent revoke (another admin, or a DisableOperator
215				// cascade) won the CAS between the GetOperatorAPIKey
216				// snapshot above and this UPDATE. Already revoked — mirror
217				// the RevokedAt != nil idempotent branch above (204, no
218				// audit row, since this actor's call did not cause the
219				// state change).
220				w.WriteHeader(http.StatusNoContent)
221				return
222			}
223			s.logger.Error("revoke api key", "error", err)
224			writeError(w, http.StatusInternalServerError, "failed to revoke api key")
225			return
226		}
227		s.recordAuditAction(r.Context(), auditOperatorAPIKeyRevoke, id, kid)
228		w.WriteHeader(http.StatusNoContent)
229	}
