37		Groups     *[]string            `json:"groups,omitempty"`
38		Role       *string              `json:"role,omitempty"`
39		PublicIP   *string              `json:"public_ip,omitempty"`
40		ListenPort *int                 `json:"listen_port,omitempty"`
41		Advanced   *models.HostAdvanced `json:"advanced,omitempty"`
