217	// renderHostConfig produces the Nebula config.yml for the given host, resolving
218	// the network's enrolled lighthouses and applying per-host advanced overrides.
219	func (s *Server) renderHostConfig(ctx context.Context, host *models.Host) ([]byte, error) {
220		lighthouses, err := s.getLighthouses(ctx, host.NetworkID)
221		if err != nil {
222			return nil, fmt.Errorf("get lighthouses: %w", err)
223		}
224	
225		// Validate family-match for unsafe_routes
226		if adv := host.Advanced; adv != nil {
227			for _, u := range adv.UnsafeRoutes {
228				routePrefix, err := netip.ParsePrefix(u.Route)
229				if err != nil {
230					return nil, fmt.Errorf("parse route %q: %w", u.Route, err)
231				}
232				viaAddr, err := netip.ParseAddr(u.Via)
233				if err != nil {
234					return nil, fmt.Errorf("parse via %q: %w", u.Via, err)
235				}
236	
237				// Check family match between route and via
238				if routePrefix.Addr().Is4() != viaAddr.Is4() {
239					family := "IPv6"
240					if routePrefix.Addr().Is4() {
241						family = "IPv4"
242					}
243					return nil, fmt.Errorf("unsafe_route family mismatch: route %s (requires %s via address) but via %s uses different family", u.Route, family, u.Via)
244				}
245	
246				// Check that host has at least one address in the same family as via
247				hasFamily := false
248				for _, addr := range host.NebulaIPs {
249					hostAddr, _ := netip.ParseAddr(addr)
250					if hostAddr.Is4() == viaAddr.Is4() {
251						hasFamily = true
252						break
253					}
254				}
255				if !hasFamily {
256					family := "IPv6"
257					if viaAddr.Is4() {
258						family = "IPv4"
259					}
260					return nil, fmt.Errorf("unsafe_route family mismatch: route %s needs %s host address but host %q has no %s addresses", u.Route, family, host.Name, family)
261				}
262			}
263		}
264	
265		input := configgen.GeneratorInput{
266			HostName:     host.Name,
267			NebulaIPs:    host.NebulaIPs,
268			IsLighthouse: host.IsLighthouse,
269			IsRelay:      host.IsRelay,
270			CACertPath:   "/etc/nebula/ca.crt",
271			CertPath:     "/etc/nebula/host.crt",
272			KeyPath:      "/etc/nebula/host.key",
273			ListenPort:   host.ListenPort,
274			Lighthouses:  lighthouses,
275			FirewallInbound: []configgen.FirewallRule{
276				{Port: "any", Proto: "icmp", Group: "any"},
277			},
278			FirewallOutbound: []configgen.FirewallRule{
279				{Port: "any", Proto: "any", Group: "any"},
280			},
281		}
282		if adv := host.Advanced; adv != nil {
283			input.PunchyOverride = adv.Punchy
284			input.ListenHost = adv.ListenHost
285			input.MTU = adv.MTU
286			input.TunDevice = adv.TunDevice
287			for _, u := range adv.UnsafeRoutes {
288				input.UnsafeRoutes = append(input.UnsafeRoutes, configgen.AdvancedUnsafeRoute{Route: u.Route, Via: u.Via})
289			}
290		}
291		return configgen.Generate(input)
292	}
