14	// buildHostPrefix parses hostIP and networkCIDR, validates they belong to the same
15	// IP family (v4/v6), and returns a prefix combining the host address with the network mask.
16	func buildHostPrefix(hostIP, networkCIDR string) (netip.Prefix, error) {
17		prefix, err := netip.ParsePrefix(networkCIDR)
18		if err != nil {
19			return netip.Prefix{}, fmt.Errorf("parse CIDR: %w", err)
20		}
21	
22		hostAddr, err := netip.ParseAddr(hostIP)
23		if err != nil {
24			return netip.Prefix{}, fmt.Errorf("parse host IP: %w", err)
25		}
26	
27		if hostAddr.Is4() != prefix.Addr().Is4() {
28			return netip.Prefix{}, fmt.Errorf("IP family mismatch: host %s vs network %s", hostIP, networkCIDR)
29		}
30	
31		return netip.PrefixFrom(hostAddr, prefix.Bits()), nil
32	}
33	
34	// buildHostPrefixes parses each hostAddr and finds a matching parent prefix from network.CIDRs.
35	// For each hostAddr[i]:
36	// - Parses the address
37	// - Finds the first CIDR that contains it
38	// - Returns a prefix using the host address with the parent's mask bits
39	// If no parent contains the address, returns an error with the address index.
40	func buildHostPrefixes(network *models.Network, hostAddrs []string) ([]netip.Prefix, error) {
41		result := make([]netip.Prefix, len(hostAddrs))
42	
43		for i, hostAddr := range hostAddrs {
44			addr, err := netip.ParseAddr(hostAddr)
45			if err != nil {
46				msg := models.FriendlyAddrError("nebula_ips["+strconv.Itoa(i)+"]", hostAddr)
47				return nil, fmt.Errorf("%s", msg)
48			}
49	
50			var found netip.Prefix
51			var foundParent bool
52			for _, cidr := range network.CIDRs {
53				parent, err := netip.ParsePrefix(cidr)
54				if err != nil {
55					return nil, fmt.Errorf("network has invalid CIDR %q: %w", cidr, err)
56				}
57	
58				if parent.Contains(addr) {
59					found = parent
60					foundParent = true
61					break
62				}
63			}
64	
65			if !foundParent {
66				return nil, fmt.Errorf("nebula_ips[%d]: %q is not within any network CIDR", i, hostAddr)
67			}
68	
69			result[i] = netip.PrefixFrom(addr, found.Bits())
70		}
71	
72		return result, nil
73	}
