75	// decodeJSONStrict decodes JSON from request body with DisallowUnknownFields enabled.
76	// On unknown field, returns helpful message suggesting legacy field names.
77	func decodeJSONStrict(r *http.Request, dst any) error {
78		dec := json.NewDecoder(r.Body)
79		dec.DisallowUnknownFields()
80		if err := dec.Decode(dst); err != nil {
81			errStr := err.Error()
82	
83			// Parse unknown field from "json: unknown field \"cidr\"" format
84			if strings.Contains(errStr, "unknown field") {
85				// Extract field name from error message
86				parts := strings.Split(errStr, "\"")
87				if len(parts) >= 2 {
88					fieldName := parts[1]
89					// Suggest proper plural form for known legacy fields
90					if fieldName == "cidr" {
91						return fmt.Errorf("unknown field 'cidr' — use 'cidrs' (array of CIDRs)")
92					}
93					if fieldName == "nebula_ip" {
94						return fmt.Errorf("unknown field 'nebula_ip' — use 'nebula_ips' (array of IPs)")
95					}
96					return fmt.Errorf("unknown field '%s'", fieldName)
97				}
98			}
99			return err
100		}
101		return nil
102	}
