	id := chi.URLParam(r, "id")
	_, err := w.store.BlockHostAndAddToBlocklist(r.Context(), id, "blocked via UI")
	if errors.Is(err, store.ErrNotFound) {
		http.NotFound(rw, r)
		return
	}
	if err != nil {
